sql:
SELECT AVG(international_fee) AS average_international_tuition_fee
FROM tuition_fees
WHERE year = 2012;

SELECT AVG(in_state_fee) AS average_in_state_fee
FROM tuition_fees
WHERE university_id = 0 AND year = 2011;

external_knowledge:
- "Prosperous states" refers to states with higher median household incomes;
- "Average tuition fee" is calculated by averaging the international fees for all universities in each state;
- "International students" are students who come from outside the state or country to study.

- "Lone Star State" is a nickname for Texas;
- "stand tall" refers to the universities that are located in Texas;
- "costs that students face" includes in-state fee, out-of-state fee, international fee, housing fee, meal plan fee, books and supplies, and other fees;
- "detailed portrait of Texas" includes the region, population, capital city, governor, senators, median income, and unemployment rate.

- "current tuition fees" refer to the most recent recorded fees for each university;
- "highest tuition fees" refer to the maximum fees recorded for any year for each university;
- "average fees for their respective states" are the average tuition fees across all universities in the same state.

sql:
SELECT COUNT(DISTINCT university_id) AS total_universities_with_international_fees
FROM tuition_fees
WHERE international_fee > 0;

external_knowledge:
